import{_ as a,c as e,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Diff 视图: 多角度审查变更 | Plannotator","description":"学习 Plannotator 代码评审中切换 diff 类型的方法。在下拉菜单中选择 uncommitted、staged、last commit 或 branch 视图，从多角度审查代码变更。","frontmatter":{"title":"Diff 视图: 多角度审查变更 | Plannotator","sidebarTitle":"5种 diff 视图切换","subtitle":"Diff 视图: 多角度审查变更","description":"学习 Plannotator 代码评审中切换 diff 类型的方法。在下拉菜单中选择 uncommitted、staged、last commit 或 branch 视图，从多角度审查代码变更。","tags":["code-review","git","diff","tutorial"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"zh/backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"zh/backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),d={name:"zh/backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function r(s,t,n,l,p,c){return i(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="切换-diff-视图" tabindex="-1">切换 Diff 视图 <a class="header-anchor" href="#切换-diff-视图" aria-label="Permalink to &quot;切换 Diff 视图&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><p>在代码评审时，你可以：</p><ul><li>用下拉菜单在 5 种 diff 视图之间快速切换</li><li>理解每种视图显示的代码变更范围</li><li>根据审查需求选择合适的 diff 类型</li><li>避免因选择错误的视图而遗漏重要变更</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p><strong>评审时只看工作区，遗漏了已暂存的文件</strong>：</p><p>你运行 <code>/plannotator-review</code> 命令，看到一些代码变更，添加了几条注释。但提交后发现，评审里漏掉了那些已经 <code>git add</code> 到暂存区的文件——这些文件根本没有出现在 diff 中。</p><p><strong>想知道当前分支和 main 分支的总体差异</strong>：</p><p>你在一个 feature 分支上开发了几周，想看看总共改了哪些东西，但默认的「未提交变更」视图只能显示最近几天的修改。</p><p><strong>想对比两个特定提交之间的差异</strong>：</p><p>你想确认某个 bug 修复是否正确，需要对比修复前后的代码，但不知道如何让 Plannotator 显示历史提交的 diff。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li><strong>全面审查时</strong>：同时查看工作区和暂存区的变更</li><li><strong>分支合并前</strong>：检查当前分支相对于 main/master 的所有改动</li><li><strong>回滚审查时</strong>：确认最后一次提交改了哪些文件</li><li><strong>多人协作时</strong>：检查同事暂存但未提交的代码</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Git diff 命令有很多变种，每个变种显示不同的代码范围。Plannotator 把这些变种集中到了一个下拉菜单里，让你不需要记住复杂的 git 命令。</p><div class="info custom-block"><p class="custom-block-title">Git Diff 类型速查</p><table tabindex="0"><thead><tr><th>diff 类型</th><th>显示范围</th><th>典型使用场景</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>工作区 + 暂存区</td><td>评审本次开发的所有修改</td></tr><tr><td>Staged changes</td><td>仅暂存区</td><td>提交前审查准备提交的内容</td></tr><tr><td>Unstaged changes</td><td>仅工作区</td><td>审查还没 <code>git add</code> 的修改</td></tr><tr><td>Last commit</td><td>最近一次提交</td><td>回滚或审查刚才的提交</td></tr><tr><td>vs main</td><td>当前分支 vs 默认分支</td><td>分支合并前全面检查</td></tr></tbody></table></div><p>下拉菜单的选项会根据你的 Git 状态动态变化：</p><ul><li>如果当前不在默认分支，会显示「vs main」选项</li><li>如果没有已暂存的文件，Staged 视图会提示「No staged changes」</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-启动代码评审" tabindex="-1">第 1 步：启动代码评审 <a class="header-anchor" href="#第-1-步-启动代码评审" aria-label="Permalink to &quot;第 1 步：启动代码评审&quot;">​</a></h3><p><strong>为什么</strong></p><p>需要先打开 Plannotator 的代码评审界面。</p><p><strong>操作</strong></p><p>在终端运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>你应该看到</strong></p><p>浏览器打开了代码评审页面，左侧文件树上方有一个下拉菜单显示当前 diff 类型（通常是「Uncommitted changes」）。</p><h3 id="第-2-步-切换到-staged-视图" tabindex="-1">第 2 步：切换到 Staged 视图 <a class="header-anchor" href="#第-2-步-切换到-staged-视图" aria-label="Permalink to &quot;第 2 步：切换到 Staged 视图&quot;">​</a></h3><p><strong>为什么</strong></p><p>查看已经 <code>git add</code> 但还没提交的文件。</p><p><strong>操作</strong></p><ol><li>点击左侧文件树上方的下拉菜单</li><li>选择「Staged changes」</li></ol><p><strong>你应该看到</strong></p><ul><li>如果有暂存文件，文件树显示这些文件</li><li>如果没有暂存文件，主区域显示：「No staged changes. Stage some files with git add.」</li></ul><h3 id="第-3-步-切换到-last-commit-视图" tabindex="-1">第 3 步：切换到 Last Commit 视图 <a class="header-anchor" href="#第-3-步-切换到-last-commit-视图" aria-label="Permalink to &quot;第 3 步：切换到 Last Commit 视图&quot;">​</a></h3><p><strong>为什么</strong></p><p>审查刚才提交的代码，确认没有问题。</p><p><strong>操作</strong></p><ol><li>再次打开下拉菜单</li><li>选择「Last commit」</li></ol><p><strong>你应该看到</strong></p><ul><li>显示最近一次提交修改的所有文件</li><li>diff 内容是 <code>HEAD~1..HEAD</code> 的差异</li></ul><h3 id="第-4-步-切换到-vs-main-视图-如果可用" tabindex="-1">第 4 步：切换到 vs main 视图（如果可用） <a class="header-anchor" href="#第-4-步-切换到-vs-main-视图-如果可用" aria-label="Permalink to &quot;第 4 步：切换到 vs main 视图（如果可用）&quot;">​</a></h3><p><strong>为什么</strong></p><p>查看当前分支相对于默认分支的所有改动。</p><p><strong>操作</strong></p><ol><li>检查下拉菜单中是否有「vs main」或「vs master」选项</li><li>如果有，选择它</li></ol><p><strong>你应该看到</strong></p><ul><li>文件树显示当前分支和默认分支之间的所有差异文件</li><li>diff 内容是 <code>main..HEAD</code> 的完整变更</li></ul><div class="tip custom-block"><p class="custom-block-title">检查当前分支</p><p>如果看不到「vs main」选项，说明你在默认分支上。可以用以下命令查看当前分支：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>切换到 feature 分支后再试：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>确认你已经掌握了：</p><ul><li>[ ] 能找到并打开 diff 类型下拉菜单</li><li>[ ] 理解「Uncommitted」「Staged」「Last commit」的区别</li><li>[ ] 能识别「vs main」选项什么时候出现</li><li>[ ] 知道在什么场景下用哪种 diff 类型</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="坑-1-评审时只看-uncommitted-漏掉了-staged-文件" tabindex="-1">坑 1：评审时只看 Uncommitted，漏掉了 Staged 文件 <a class="header-anchor" href="#坑-1-评审时只看-uncommitted-漏掉了-staged-文件" aria-label="Permalink to &quot;坑 1：评审时只看 Uncommitted，漏掉了 Staged 文件&quot;">​</a></h3><p><strong>症状</strong></p><p>提交后发现评审漏掉了一些已暂存的文件。</p><p><strong>原因</strong></p><p>Uncommitted 视图显示工作区和暂存区的所有变更（<code>git diff HEAD</code>），已暂存的文件也会包含其中。</p><p><strong>解决</strong></p><p>评审前先切到 Staged 视图检查一遍，或者用 Uncommitted 视图（包含暂存区）。</p><h3 id="坑-2-分支合并前没有对比-main" tabindex="-1">坑 2：分支合并前没有对比 main <a class="header-anchor" href="#坑-2-分支合并前没有对比-main" aria-label="Permalink to &quot;坑 2：分支合并前没有对比 main&quot;">​</a></h3><p><strong>症状</strong></p><p>合并到 main 后发现引入了不相关的修改。</p><p><strong>原因</strong></p><p>只看了最近几天的提交，没有对比整个分支相对于 main 的差异。</p><p><strong>解决</strong></p><p>合并前用「vs main」视图全面检查一遍。</p><h3 id="坑-3-以为切换视图会丢失注释" tabindex="-1">坑 3：以为切换视图会丢失注释 <a class="header-anchor" href="#坑-3-以为切换视图会丢失注释" aria-label="Permalink to &quot;坑 3：以为切换视图会丢失注释&quot;">​</a></h3><p><strong>症状</strong></p><p>不敢切换 diff 类型，担心之前添加的注释会消失。</p><p><strong>原因</strong></p><p>误解了切换机制。</p><p><strong>实际情况</strong></p><p>切换 diff 类型时，Plannotator 会保留之前的注释——它们可能仍然适用，或者你可以手动删除不相关的注释。</p><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Plannotator 支持的 5 种 diff 类型：</p><table tabindex="0"><thead><tr><th>类型</th><th>Git 命令</th><th>场景</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>评审本次开发的所有修改</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>提交前审查暂存区</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>审查工作区修改</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>回滚或审查最近提交</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>分支合并前全面检查</td></tr></tbody></table><p>切换视图不会丢失注释，你可以在不同视角下查看同一批或新的注释。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../advanced/url-sharing/">URL 分享</a></strong>。</p><p>你会学到：</p><ul><li>如何将评审内容压缩到 URL 中分享给同事</li><li>接收方如何打开共享的评审链接</li><li>分享模式下的限制和注意事项</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Diff 类型定义</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Git 上下文获取</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>运行 Git Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Diff 切换处理</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>文件树中的 Diff 选项渲染</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>关键类型</strong>：</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>关键函数</strong>：</p><ul><li><code>getGitContext()</code>: 获取当前分支、默认分支和可用的 diff 选项</li><li><code>runGitDiff(diffType, defaultBranch)</code>: 根据 diff 类型执行对应的 git 命令</li></ul><p><strong>关键 API</strong>：</p><ul><li><code>POST /api/diff/switch</code>: 切换 diff 类型，返回新的 diff 数据</li></ul></details>',83)])])}const f=a(d,[["render",r]]);export{g as __pageData,f as default};
